class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        int MOD = 1e9 + 7;
        int dp[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            dp[i] = (dp[i - 1] + (i >= delay ? dp[i - delay - 1] : 0) + (i >= forget ? dp[i - forget - 1] : 0)) % MOD;
        }
        return dp[n];
    }
};
```

